ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?street_address ?city WHERE {
  ?t a :Transactions .
  ?p a :Properties .
  ?t p:hasProperties ?p .
  ?p p:Street_Address ?street_address .
  ?p p:City ?city .
  ?t p:TypeOfTransaction ?typeoftransaction_lk .
  FILTER(REGEX(STR(?typeoftransaction_lk), "^Rent$"))
} }
  component: { SELECT ?street_address WHERE {
  ?t a :Transactions .
  ?p a :Properties .
  ?t p:hasProperties ?p .
  ?p p:Street_Address ?street_address .
  ?t p:TypeOfTransaction ?typeoftransaction_lk .
  FILTER(REGEX(STR(?typeoftransaction_lk), "^Rent$"))
} }
  component_2: { SELECT ?city WHERE {
  ?t a :Transactions .
  ?p a :Properties .
  ?t p:hasProperties ?p .
  ?p p:City ?city .
  ?t p:TypeOfTransaction ?typeoftransaction_lk .
  FILTER(REGEX(STR(?typeoftransaction_lk), "^Rent$"))
} }
}

PREFIX : <http://ambrosia.example.org/housingmarket#>
PREFIX p: <http://ambrosia.example.org/housingmarket/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?city WHERE {
  ?clientproperties a :ClientProperties .
  ?c a :Clients .
  ?clientproperties p:hasClients ?c .
  ?p a :Properties .
  ?clientproperties p:hasProperties ?p .
  ?p p:City ?city .
  ?c p:PhoneNumber ?phonenumber_lk .
  FILTER(REGEX(STR(?phonenumber_lk), "^555\\-333\\-4444$"))
} }
  component_2: { SELECT ?street_address WHERE {
  ?clientproperties a :ClientProperties .
  ?c a :Clients .
